import { SET_MESSAGE, CLEAR_MESSAGE,READ_MESSAGE } from "../actions/types";

const initialState = {};

export default function (state = initialState, action) {
  const { type, payload } = action;

  switch (type) {
    case SET_MESSAGE:
      return { message: payload };

    case READ_MESSAGE:
      return { 
        ...state,
        message: action.payload 
      };

    case CLEAR_MESSAGE:
      return { message: "" };

    default:
      return state;
  }
}