import React, { Component } from "react";

class CheckBox extends Component {
  constructor() {
    super();
    this.state = {
      selectedOptions: []
    };
    this.handleCheckboxChange = this.handleCheckboxChange.bind(this);
  }

  handleCheckboxChange(event) {
    const { value, checked } = event.target;
    this.setState(
      (prevState) => {
        const newSelectedOptions = checked
          ? [...prevState.selectedOptions, value]
          : prevState.selectedOptions.filter((option) => option !== value);

        return {
          selectedOptions: newSelectedOptions
        };
      },
      () => {
        // Call the callback function passed as a prop with the updated state
        this.props.onSelectedOptionsChange(this.state.selectedOptions);
      }
    );
  }


  render() {
    return (
        <div className="form-group">
        <label className="bold-label" htmlFor="options">Courses</label>
        <div className="radio-group"> 
          <label>
            <input
              type="checkbox"
              value="Option1"
              onChange={this.handleCheckboxChange}
            /> Java
          </label>
          <label>
            <input
              type="checkbox"
              value="Option2"
              onChange={this.handleCheckboxChange}
            /> .Net
          </label>
          <label>
            <input
              type="checkbox"
              value="Option3"
              onChange={this.handleCheckboxChange}
            /> PHP
          </label>
        </div>
       
      </div>
    );
  }
}

export default CheckBox;
