import React, { useState } from 'react';

const Dropdown = ({ country, handleDropdownChange }) => {

  const handleChange = (event) => {
    handleDropdownChange(event.target.value);
  };
  return (
    <div className="form-group">
      <label className="bold-label" htmlFor="dropdown">Country:</label>
      <select id="dropdown" name="dropdown" value={country} onChange={handleChange}>
        <option value="">--Please choose an country--</option>
        <option value="option1">IND</option>
        <option value="option2">USA</option>
        <option value="option3">UK</option>
      </select>
    </div>
  );
};

export default Dropdown;